#!/bin/bash
set -euo pipefail

TMPDIR=$(mktemp -d)
trap 'rm -rf "$TMPDIR"' EXIT

log() {
  echo "[$(date +'%Y-%m-%d %H:%M:%S')] $*" >&2
}

die() {
  log "ERROR: $*"
  exit 1
}

FILE=""
COUNT=10
while getopts "f:n:h" opt; do
  case $opt in
    f) FILE="$OPTARG" ;;
    n) COUNT="$OPTARG" ;;
    h) usage ;;
    *) usage ;;
  esac
done
[[ -z "$FILE" ]] && die "File is required"
[[ -f "$FILE" ]] || die "File not found: $FILE"

log "Processing $FILE with count=$COUNT"
head -n "$COUNT" "$FILE" > "$TMPDIR/output.txt"
log "Done"
